# Agent that reads quality certificate before retrieval
from dataclasses import dataclass

@dataclass
class RetrievalConfig:
    dataset_id: str
    version: str
    min_dq_score: float = 0.95  # 95% minimum composite DQ score

class QualityAwareAgent:
    def __init__(self, dq_client, retriever, human_review_queue):
        self.dq = dq_client
        self.retriever = retriever
        self.queue = human_review_queue

    def retrieve_context(self, query: str, config: RetrievalConfig) -> dict:
        cert = self.dq.get_quality_cert(config.dataset_id, config.version)

        if cert["status"] == "quarantined":
            return {"error": "dataset_quarantined", "data": None, "confidence": 0.0}

        if cert["composite_score"] is None or cert["composite_score"] < config.min_dq_score:
            # Route to human review
            self.queue.submit({"query": query, "cert": cert})
            return {"error": "low_quality_data", "data": None, "confidence": cert.get("composite_score", 0.0)}

        data = self.retriever.retrieve(query, config.dataset_id, config.version)
        return {"data": data, "confidence": cert["composite_score"], "dq_score": cert["composite_score"]}
